var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"HILDE_FENRIR_NEXT_NULL","text":{"KOREA":"......도망쳤나?","JPN":"……退散か？","ENG":"Did she run?","TWN":"……逃跑了嗎？"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"HILDE_FENRIR_NEXT_NULL","text":{"KOREA":"다른 녀석들도 더 이상 부활하지 않는 걸 보니 아무래도 불멸체 코어를 파괴하는 데 성공했나 보군.","JPN":"他の奴らも復活しないってことは、どうやら不滅体コアの破壊に成功したようだな。","ENG":"The rest of the Replacers are not regenerating anymore. It seems they managed to destroy the Immortal System Core.","TWN":"其他人也不再復活了，看來成功破壞不滅者核心了。"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"HILDE_FENRIR_NEXT_NULL","text":{"KOREA":"남은 건...... 신입 애송이가 직접 극복해야 할 일이겠지.","JPN":"後は……新人が自分で乗り越えなきゃな。","ENG":"And what's to come will rest upon the hands of the rookie herself.","TWN":"剩下的……就是新人小鬼得直接克服的事情了。"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"HILDE_FENRIR_NEXT_NULL","text":{"KOREA":"그렇지 않으면...... 이번에도 미래는 없을 테니까.","JPN":"そうしなければ……今回も未来はないだろう。","ENG":"If she fails, there will be no future this time around either.","TWN":"不然的話……這次也不會有未來。"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"ASMODEUS_FALLEN_NULL_QM","text":{"KOREA":"못 보던 사이에 성인군자가 다 되셨군. 힐데.","JPN":"見ない間に、聖人にでもなったつもりか？　ヒルデ。","ENG":"Wow, you almost sound like a saint, Hilde.","TWN":"好久不見的這段時間，妳也變成了聖人君子了呢，希爾德。"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":"HILDE_FENRIR_NEXT_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"ASMODEUS_FALLEN_NULL_QM","text":{"KOREA":"다들 스승이라고 떠받들어 줘서 그런가...... 그 짓거리도 꽤 어울리는걸?","JPN":"みんなが師匠、師匠とあがめてくれるからか？　偉そうなマネも、ずいぶん馴染んできたな。","ENG":"Maybe it's because everyone calls you Master. I must say, what you're doing suits you.","TWN":"是因為大家都遵奉妳為師父……所以這惡劣玩笑才那麼合適嗎？"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASMODEUS_FALLEN_NULL_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"ASMODEUS_FALLEN_NULL_QM","text":{"KOREA":"물론 네 본성을 아무도 모를 때의 이야기지만.","JPN":"もちろん、其方の本性を知らないからだろうが。","ENG":"I just hope that no one finds out about your true colors.","TWN":"當然，那是在沒有人知道妳的本性的時候。"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASMODEUS_FALLEN_NULL_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"HILDE_FENRIR_NEXT_NULL","text":{"KOREA":"언제쯤 나타날지 궁금했는데 이제야 무거운 엉덩이를 뗐나 보군.","JPN":"いつ現れるか気になってたが、やっと重い腰を上げたのか。","ENG":"So you finally decided to move your butt. I was wondering when that'd be.","TWN":"因為不知道什麼時候才能出現，所以妳的大屁股已經坐不住了嗎？"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"ASMODEUS_FALLEN_NULL_QM","text":{"KOREA":"아니? 난 지금도 앉아 있는데?","JPN":"いや？　今も変わらず座ってるのじゃ。","ENG":"Oh, my butt hasn't been lifted at all, Hilde.","TWN":"沒有啊？我現在還坐著啊？"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASMODEUS_FALLEN_NULL_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"ASMODEUS_FALLEN_NULL_QM","text":{"KOREA":"내 엉덩이를 들어올리고 싶으면 좀 더 분발해야 할 거야, 힐데.","JPN":"妾の腰を上げさせたいなら、もう少し頑張りが必要であろう、ヒルデ。","ENG":"You're going to have to work much harder to make me lift my butt.","TWN":"想要抬起我的屁股，妳還得再努力一點啊，希爾德。"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASMODEUS_FALLEN_NULL_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"ASMODEUS_FALLEN_NULL_QM","text":{"KOREA":"사실 조금 전부터 보고 있었는데...... 그 반편이를 상대로 헉헉대는 네 꼴사나운 모습이 아주 재미있었거든.","JPN":"さっきから見ておったが……あの間抜けにさえ苦戦するお前のみっともない姿が、実に見ものじゃった。","ENG":"I've been watching you for quite a while, actually. It was hilarious that you were trying so hard to get yourself together against that puny thing.","TWN":"我剛剛就在看……妳在對付那個半吊子時，氣喘吁吁的醜陋模樣非常有趣呢。"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASMODEUS_FALLEN_NULL_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"ASMODEUS_FALLEN_NULL_QM","text":{"KOREA":"좋아하던 스타가 영락한 모습을 보는 것 같아서 마음이 아파.","JPN":"昔好きだったスターが地に落ちたところを見ているようで、心が痛むのじゃ。","ENG":"My heart breaks for you, likes a fan does for a star that lost all of her past glamour.","TWN":"就好像是看到曾經喜歡的明星落魄潦倒的樣子，真令人心痛。"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASMODEUS_FALLEN_NULL_QM","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"ASMODEUS_FALLEN_NULL_QM","text":{"KOREA":"네가 전력을 개방했다면 불멸체 코어 같은 장난감이 재생 같은 귀여운 짓을 하진 못했을 텐데......","JPN":"其方が全力を出していれば、不滅体コアごときオモチャが、再生みたいなイタズラはできなかったはず……","ENG":"That toy named Immortal System Core wouldn't have pulled off those cute stunts like regeneration if you had unleashed your power to the fullest.","TWN":"妳要是使出全力的話，像不滅者核心那種玩具，應該也沒辦法做再生這種這麼可愛的事情吧……"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASMODEUS_FALLEN_NULL_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"ASMODEUS_FALLEN_NULL_QM","text":{"KOREA":"단말을 넘어 본체까지 인과 연결의 타격이 갔을 테니까. 그렇지 않아?","JPN":"端末を越え、本体まで打撃があったはずじゃ。そうじゃろう？","ENG":"The damage to the terminal would have been so great that it would have destroyed the core connected to it. Don't you agree?","TWN":"那應該能越過終端，連本體都受到因果上的打擊吧。不是嗎？"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASMODEUS_FALLEN_NULL_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"HILDE_FENRIR_NEXT_NULL","text":{"KOREA":"......누구 좋으라고 내가 그런 짓을 하지?","JPN":"……誰のために、私がわざわざそんなことを？","ENG":"And who would I be doing that for?","TWN":"我為什麼要對別人言聽計從，去做這件事？"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"ASMODEUS_FALLEN_NULL_QM","text":{"KOREA":"하하, 하긴 그렇지.","JPN":"ハハ、まあ、そうじゃろうな。","ENG":"Hah hah, you got me.","TWN":"哈哈，說得也是。"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASMODEUS_FALLEN_NULL_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"ASMODEUS_FALLEN_NULL_QM","text":{"KOREA":"네가 전력을 개방할 정도의 클리포트 인자가 활성화 됐으면 벌써 클리포트의 마왕들이 모두 깨어났을 테니까.","JPN":"其方が全力を出すほどのクリフォト・ファクターが活性化していたら、\\nクリフォトの魔王ら全員がとっくに目覚めていただろう。","ENG":"If you activated enough Qliphoth Factors to release your full power, you would have awakened all the Demon Lord of Qliphoth.","TWN":"要是妳使出全力，使得逆卡巴拉因子活性化的話，逆卡巴拉魔王們會全部醒過來吧。"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASMODEUS_FALLEN_NULL_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"HILDE_FENRIR_NEXT_NULL","text":{"KOREA":"......지금 깨어난 건 누구지?","JPN":"……今、目覚めているのは誰だ？","ENG":"How many of you are awake?","TWN":"……現在醒過來的有誰？"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"ASMODEUS_FALLEN_NULL_QM","text":{"KOREA":"글쎄? 나와...... 가짜 구세주 정도?","JPN":"どうじゃろう？　妾と……ニセ救世主ぐらいだろうか？","ENG":"I don’t know. There's me, and the False Savior.","TWN":"這個嘛……我和……偽救世主？"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASMODEUS_FALLEN_NULL_QM","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"ASMODEUS_FALLEN_NULL_QM","text":{"KOREA":"그 외에도 한두 명 더 있을 것 같은데...... 확실히는 잘 모르겠네.","JPN":"他にも１、２名はいそうじゃが……正確にはわからんのじゃ。","ENG":"There could be a few more, but I'm not sure.","TWN":"除此之外，好像還有一兩個人……不是很確定。"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASMODEUS_FALLEN_NULL_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"HILDE_FENRIR_NEXT_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"ASMODEUS_FALLEN_NULL_QM","text":{"KOREA":"아, 너무 걱정하지 않아도 돼.","JPN":"あ、でもそんなに心配いらないのじゃ。","ENG":"Ah, you don’t have to worry too much.","TWN":"啊，妳可以不用太擔心。"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASMODEUS_FALLEN_NULL_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"ASMODEUS_FALLEN_NULL_QM","text":{"KOREA":"깨어나긴 했지만 아직은 힘이 부족하니까...... 당분간은 조용히 죽어 지낼 거야.","JPN":"目覚めてはいても、まだ力が足りないからな……しばらくはおとなしく隠居するつもりじゃ。","ENG":"I'm awake, but I'm still weak. I'll be lying low for the time being.","TWN":"就算醒來了，但力量還不夠……暫時只能靜靜地躺在那裡。"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASMODEUS_FALLEN_NULL_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"ASMODEUS_FALLEN_NULL_QM","text":{"KOREA":"다시 보는 건 아마도......","JPN":"再会するのは、おそらく……","ENG":"I'll be seeing you around...","TWN":"妳再次看到我們，恐怕會在……"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASMODEUS_FALLEN_NULL_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"HILDE_FENRIR_NEXT_NULL","text":{"KOREA":"......클리포트 게임이겠지.","JPN":"……クリフォトゲームになるだろうな。","ENG":"the Qliphoth Game, I guess.","TWN":"……逆卡巴拉遊戲。"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"ASMODEUS_FALLEN_NULL_QM","text":{"KOREA":"그래. 게임이 시작될 때 보게 되겠지.","JPN":"そう、ゲームが始まる時に再会するじゃろう。","ENG":"Yes. We'll meet again when the game starts.","TWN":"沒錯。遊戲開始時就會看到我們了。"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASMODEUS_FALLEN_NULL_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"ASMODEUS_FALLEN_NULL_QM","text":{"KOREA":"그럼 잘 지내라고, 힐데.","JPN":"それでは元気でな、ヒルデ。","ENG":"Take care now, Hilde.","TWN":"那保重囉，希爾德。"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASMODEUS_FALLEN_NULL_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"ASMODEUS_FALLEN_NULL_QM","text":{"KOREA":"그동안 꽤 녹슨 것 같은데 칼 쓰는 연습도 좀 하고.","JPN":"腕が鈍ってるみたいだから、剣術の訓練でもすると良いじゃろう。","ENG":"And make sure you work on your swings. Your sword skills have gotten rusty.","TWN":"這段時間妳身手都變遲鈍了，去多練練妳的刀法吧。"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASMODEUS_FALLEN_NULL_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"HILDE_FENRIR_NEXT_NULL","text":{"KOREA":"너야말로 다음에는 신발이나 신고 오도록.","JPN":"お前のほうこそ、次は靴でも履いてくるんだな。","ENG":"And you make sure you wear your shoes next time,","TWN":"妳才是，下次穿好鞋子吧。"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"HILDE_FENRIR_NEXT_NULL","text":{"KOREA":"아스모데우스.","JPN":"アスモデウス。","ENG":"Asmodeus.","TWN":"阿斯蒙蒂斯。"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"ASMODEUS_FALLEN_NULL_NULL","text":{"KOREA":"하하하하하하하!","JPN":"ハハハハハハハ！","ENG":"Hah hah hah!","TWN":"哈哈哈哈哈哈哈！"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASMODEUS_FALLEN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}},"sfx":"FX_COMBAT_ALL_EARTHQUAKE_03"},{"id":"L35_1","type":"dialog","speaker":"ASMODEUS_FALLEN_NULL_NULL","text":{"KOREA":"내 부하들은 이걸로 밟아 주면 좋아하던데 넌 취향이 좀 다른가 봐?","JPN":"妾の部下たちはこれで踏むと喜ぶのじゃが、其方はそうでもないのか？","ENG":"My followers love it to death when I tread on them barefooted. I bet it doesn't suit your taste.","TWN":"我的部下都喜歡被我這樣踩，不過妳應該不太喜歡吧？"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASMODEUS_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"HILDE_FENRIR_NEXT_NULL","text":{"KOREA":"닥쳐, 이만 꺼져라.","JPN":"黙れ、とっとと消えろ。","ENG":"Shut up and get lost.","TWN":"閉嘴，給我滾。"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"HILDE_FENRIR_NEXT_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"당신이 그 코핀 컴퍼니의 힐데 소대장이로군요.","JPN":"あなたがあのコフィンカンパニーのヒルデ小隊長ですか。","ENG":"You're Commander Hilde of the Coffin Company.","TWN":"妳就是那個科芬公司的小隊長希爾德吧。"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"전 특수전 부대 델타세븐의 지휘관인 마리아 안토노프입니다.","JPN":"私は特殊戦部隊、デルタセブンの指揮官を務めるマリア・アントノフです。","ENG":"I'm Maria Antonov, Commander of the special forces unit Delta Seven.","TWN":"我是特種作戰部隊第七三角洲部隊的指揮官瑪麗亞·安東諾夫。"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"도움에 감사드립니다.","JPN":"助力に感謝します。","ENG":"I would like to express my thanks.","TWN":"非常感謝你們的幫助。"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"당신의 조력이 없었으면 꽤 많이 곤란해졌을 것 같군요.","JPN":"あなたの助力がなければ、困ったことになっていたでしょう。","ENG":"Things could have gotten much worse if it weren't for you.","TWN":"沒有你們的幫助，我們肯定會很艱難吧。"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"HILDE_FENRIR_NEXT_NULL","text":{"KOREA":"각자 나눠서 상대한 것뿐인데 굳이 감사랄 것까지야......","JPN":"それぞれ分担して相手しただけであって、感謝されるほどでも……","ENG":"You did as much work as I did. There's no need to thank me,","TWN":"我們是分別對付不同的敵人，沒必要特別說謝謝……"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"HILDE_FENRIR_NEXT_NULL","text":{"KOREA":"결국 놓쳐버리기도 했고......","JPN":"結局逃してしまったしな……","ENG":"especially when I let them get away...","TWN":"我最後也失手了……"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L2_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"어, 어이...... 이봐, 당신...... 내가 아는 그 사람 맞지?","JPN":"あ、あのお……ちょっと……アタシの知っている、ヒルデ小隊長よね？","ENG":"H-hey... Hey, you... Are you the same person I know?","TWN":"喂喂……喂，妳……真的是我認識的那個人嗎？"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L4_1","type":"dialog","speaker":"HILDE_FENRIR_NEXT_NULL","text":{"KOREA":"......맞다.","JPN":"……そうだ。","ENG":"I am.","TWN":"……是啊。"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"HILDE_FENRIR_NEXT_NULL","text":{"KOREA":"나도 내가 아는 당신이 맞는지 궁금하군. 뭘 그렇게 눈치를 보고 그러지?","JPN":"お前も、私の知っているシルビアで間違いないか？　なぜそんなによそよそしい？","ENG":"I'm starting to wonder if you're the same person I know. Why are you acting so weird all of a sudden?","TWN":"我也很好奇妳是不是我認識的那個人。妳幹嘛要這樣看人臉色？"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"하, 하지만...... 그때도 대단한 실력자라고 생각하긴 했는데......","JPN":"だ、だって……あの時も凄い腕前だとは思ったけど……","ENG":"B-but... I thought you were skilled in combat when I saw you last time,","TWN":"可、可是……我那時也覺得妳是個很強的實力者……"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"아무리 그래도 이건 좀 상식에 어긋난다고 생각하지 않아?","JPN":"いくら何でも、これは少し常識外れだと思わない？","ENG":"but don't you think what you just did there goes against common sense?","TWN":"但不管怎麼說，這也未免太超乎常理了吧？"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"HILDE_FENRIR_NEXT_NULL","text":{"KOREA":"그건......","JPN":"それは……","ENG":"Well...","TWN":"這……"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"그건 제가 설명 드리죠.","JPN":"それは私が説明いたしましょう。","ENG":"Let me explain.","TWN":"這就讓我來說明吧。"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"아, 아줌마?","JPN":"お、おばさん？","ENG":"O-Old Lady?","TWN":"大、大嬸？"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"오랜만입니다, 실비아 양. 건강한 것 같아 기쁘군요.","JPN":"しばらくです、シルビアさん。お元気そうで何よりです。","ENG":"It's been a while, Sylvia. I'm glad you're well.","TWN":"好久不見，希爾維亞小姐。很高興看到妳這麼有精神的樣子。"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"하지만 인사는 조금 있다가 나누도록 하죠. 먼저 궁금한 게 많으실 테니까요.","JPN":"でも、あいさつは後にしましょう。まずは、聞きたいことがたくさんあるでしょうから。","ENG":"But let's save our greetings for later. You must have a lot of questions about this.","TWN":"不過寒暄還是待會再說吧。畢竟妳好像有很多想要知道的事情。"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"으, 응...... 알겠어.","JPN":"う、うん……わかった。","ENG":"Y-yeah, okay.","TWN":"嗯，嗯……知道了。"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"아무래도 가장 궁금한 건...... 조금 전 교전한 리플레이서 퀸,","JPN":"やっぱり最も気になるのは……さっき交戦したリプレイサー・クイーンのこと、","ENG":"I bet your biggest question would be how she was able to fight the Replacer Queen,","TWN":"妳最好奇的應該是……不久前和你們交戰的克隆女皇……"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"준 5종 침식체급의 적을 어떻게 상대할 수 있었느냐 하는 거겠죠?","JPN":"第5種侵食体に準ずる敵をどうやって相手できたか、ですよね？","ENG":"a fierce enemy rated to be as powerful as a Category 5 C.O.","TWN":"也就是侵蝕階級準5級的敵人，這我們是怎麼對抗的吧？"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"확실히 놀라운 모습이었다는 점은 인정하지 않을 수 없을 것 같군요.","JPN":"確かに、驚くべき姿だったのは認めざるを得ません。","ENG":"I must admit, it was surely a startling sight to behold.","TWN":"不得不承認，這確實很令人震驚。"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"관리국은 이전의 실패를 답습하지 않기 위해 지속적인 기술 개발을 진행해 왔습니다.","JPN":"管理局は以前の失敗を踏襲しないために、持続的な技術開発を進めてきました。","ENG":"In fact, the Administration has been making constant effort in technical development to avoid repeating past failures.","TWN":"管理局為了避免重蹈過去的失敗，一直持續在進行技術開發。"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"프로토타입이긴 하지만, 최근 관리국은 제 5종 침식체에도 대응할 수 있는 통칭 테크 레벨 5의 장비를 개발하는 데 성공했습니다.","JPN":"プロトタイプではありますが、最近管理局は、\\n第5種侵食体にも対応できる通称テックレベル5の装備を開発するのに成功しました。","ENG":"Although still in a prototype stage, they recently succeeded in developing a line of equipment collectively called Tech Level 5 gear, a viable countermeasure against a Category 5 C.O.","TWN":"雖然還只是樣品，但最近管理局成功開發出能夠對付5級侵蝕體，通稱技術等級5級的裝備。"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"해당 장비들은 그 테스트를 위해 저희 쪽에 제공되었었고요.","JPN":"その装備は、テストのために我々に提供されていましたが、","ENG":"And we were provided with a set for testing.","TWN":"為了進行測試，所以管理局把這些裝備提供給了我們。"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"이제 실전 테스트가 끝난 셈이니 관련 기술들은 절차를 거쳐 각 태스크포스에 전달될 겁니다.","JPN":"すでに実戦テストが済んだようなものなので、\\n関連技術は手順を踏んで各々のタスクフォースに配布されるでしょう。","ENG":"That was the final field test. All the related engineering blueprints will be distributed to each TASKFORCE organization through the proper procedures.","TWN":"現在實戰測試已經結束了，之後相關技術會經過一定流程，傳達給各特遣勢力公司的。"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"......라고 하더군요.","JPN":"……ということです。","ENG":"Or so I was told.","TWN":"……他們是這們說的。"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"......제 5종 침식체에도 대응할 수 있는 장비를 개발했다니, 그거 기쁜 소식이군요.","JPN":"……第5種侵食体にも対応できる装備を開発したなんて、それは嬉しいニュースですね。","ENG":"It's good news that we won't be going against Category 5 C.O.s with nothing.","TWN":"……竟然開發出可以對付第5級侵蝕體的裝備，真是個令人高興的消息。"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L30_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"하지만 신기하군요.","JPN":"しかし、不思議な話です。","ENG":"But it's odd.","TWN":"但有點奇怪呢。"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"관리국은 어떻게 여기에 제 5종 침식체에 준하는 적이 등장할 걸 알고 당신들에게 신장비의 실전 테스트를 맡긴 걸까요?","JPN":"管理局はここに第5種侵食体に準ずる敵が登場することをどう把握して、\\nあなた方に新しい装備の実戦テストを頼んだのでしょうか？","ENG":"How did the Administration know that you were going to fight a Category 5 C.O. here, and had you run a field test?","TWN":"管理局怎麼知道這裡會出現第5級侵蝕體，又託你們進行新裝備的實戰測試？"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"......글쎄요.","JPN":"……どうでしょう。","ENG":"Beats me.","TWN":"……誰知道呢。"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"저희 같은 소규모 회사는 그저 시키는 대로 할 뿐이라......","JPN":"弊社みたいに小さな会社は、指示どおりにやるだけですので……","ENG":"A small company like us doesn't get to ask questions...","TWN":"我們這種小公司，也只是奉命行事而已……"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"궁금하시면 관리국에 직접 문의해 보시죠.","JPN":"気になるようでしたら、管理局に直接問い合わせて頂ければ。","ENG":"I'm afraid you'll have to ask the Administration yourself.","TWN":"如果您對此有什麼疑問之處，請直接詢問管理局吧。"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"당연히 그렇겠지요. 물론 나도 관리국에 문의할 생각은 없습니다.","JPN":"まあそうでしょう。もちろん、私も管理局に問い合わせるつもりはありません。","ENG":"Right. Of course, I don't think I would make any inquiries either.","TWN":"貴公司當然是奉命行事了，我也沒有想要諮詢管理局的意思。"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"나 정도의 직위에 있게 되면 관리국의 거절용 매크로 답변에도 일일이 보고서를 써야 할 테니까요. 귀찮은 일이지요.","JPN":"私の肩書きだと、管理局のテンプレート回答にもいちいち\\n報告書をまとめることになりますから、面倒なだけです。","ENG":"Someone in my position would have to write all kinds of detailed reports about an auto-reply rejection I'd receive from them. That'd be too much of a hassle.","TWN":"畢竟到了我這職位，就算收到管理局的婉拒自動答覆也得一一寫報告，很麻煩的。"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"역시 궁금한 게 있으면 직접 알아보는 게 제일 좋지. 그렇게 생각하지 않나요?","JPN":"やはり気になることがあったら、自ら調べるのが一番。そう思いませんか？","ENG":"If you're curious about something, it's always best to dig into it yourself. Don't you think so?","TWN":"有什麼想知道的事還是直接問最好。妳不這麼認為嗎？"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"......동감입니다.","JPN":"……同感です。","ENG":"I agree.","TWN":"……我也有同感呢。"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"그럼 저희는 실종된 저희 사원들을 찾으러 가 보도록 하겠습니다.","JPN":"それでは、私たちは行方不明の社員を捜しに行こうと思います。","ENG":"Then we'll go start looking for our missing staff.","TWN":"那我們要去找本公司行蹤不明的員工了。"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"사원들을 무사히 찾길 바라겠습니다. 행운을 빌지요.","JPN":"無事に見つかりますよう、幸運を祈ります。","ENG":"I hope they're well. Good luck.","TWN":"希望你們能平安找回員工。祝你們好運。"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"감사합니다. 그럼 이만.","JPN":"ありがとうございます。それでは。","ENG":"Thank you. Now if you’ll excuse me.","TWN":"謝謝！告辭了。"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"관리국이라......","JPN":"管理局か……","ENG":"The Administration, huh...","TWN":"管理局……"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"예전이나 지금이나 멋대로 구는 건 마찬가지군.","JPN":"今も昔も、好き勝手なのは相変わらずだな。","ENG":"I'm sick of them having everything their own way.","TWN":"不管是過去還是現在，都一樣任性啊。"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};